/**
 * CRITICAL MILEAGE ENGINE FILE
 * Do not edit this file for UI-only changes.
 * Any change here requires regression testing for:
 * - GPS tracking
 * - background tracking
 * - auto trip ending
 * - mileage calculation
 * - report generation
 * - email delivery
 *
 * VITAL — BUSINESS CRITICAL (MP-043)
 * Native GPS bridge: expo-location → handlePos in index.html.
 * Do not modify without reading docs/TRACKING_CONTRACT.md
 */
(function (global) {
  'use strict';

  const NATIVE_LOCATION_WHEN_IN_USE =
    'MilePilot uses location to record your business journeys while you are working.';
  const NATIVE_LOCATION_ALWAYS =
    'MilePilot uses background location so your mileage can continue recording when your phone is locked.';

  let deps = null;
  let nativeWatchId = null;
  let backgroundActive = false;
  let lastPermissionStatus = 'unknown';
  let permissionListeners = [];
  let logBuffer = [];

  function log(msg, data) {
    const entry = { t: new Date().toISOString(), msg: msg, data: data || null };
    logBuffer.push(entry);
    if (logBuffer.length > 200) logBuffer.shift();
    try {
      console.log('[MPTrackingProvider]', msg, data || '');
    } catch (e) {}
  }

  function isExpoNative() {
    return global.MPPlatform && global.MPPlatform.isExpoNative && global.MPPlatform.isExpoNative();
  }

  function getMode() {
    if (global.MPPlatform && global.MPPlatform.getRuntimeMode) {
      return global.MPPlatform.getRuntimeMode();
    }
    return 'browser';
  }

  function isNative() {
    return getMode() === 'native';
  }

  function isWebShell() {
    return !isNative();
  }

  function getGeolocationPlugin() {
    try {
      if (global.Capacitor && global.Capacitor.Plugins && global.Capacitor.Plugins.Geolocation) {
        return global.Capacitor.Plugins.Geolocation;
      }
    } catch (e) {}
    return null;
  }

  function expoMsgToBrowserPosition(msg) {
    if (!msg || !msg.coords) return null;
    return {
      coords: {
        latitude: msg.coords.latitude,
        longitude: msg.coords.longitude,
        accuracy: msg.coords.accuracy,
        altitude: msg.coords.altitude,
        altitudeAccuracy: msg.coords.altitudeAccuracy,
        heading: msg.coords.heading,
        speed: msg.coords.speed,
      },
      timestamp: msg.timestamp || Date.now(),
    };
  }

  function capToBrowserPosition(capPos) {
    if (!capPos || !capPos.coords) return null;
    return {
      coords: {
        latitude: capPos.coords.latitude,
        longitude: capPos.coords.longitude,
        accuracy: capPos.coords.accuracy,
        altitude: capPos.coords.altitude,
        altitudeAccuracy: capPos.coords.altitudeAccuracy,
        heading: capPos.coords.heading,
        speed: capPos.coords.speed,
      },
      timestamp: capPos.timestamp || Date.now(),
    };
  }

  function notifyPermissionChange(status) {
    if (status === lastPermissionStatus) return;
    lastPermissionStatus = status;
    permissionListeners.forEach(function (fn) {
      try {
        fn(status);
      } catch (e) {}
    });
  }

  function init(hookDeps) {
    deps = hookDeps || {};
    log('init', { mode: getMode(), provider: isExpoNative() ? 'expo' : isNative() ? 'capacitor' : 'web' });
    if (isNative()) {
      queryPermissionStatus().catch(function () {});
    }
  }

  async function expoBridgeRequest(type, payload) {
    if (!global.MPExpoBridge || !global.MPExpoBridge.request) {
      log('MPExpoBridge unavailable');
      return null;
    }
    return global.MPExpoBridge.request(type, payload || {});
  }

  async function queryPermissionStatus() {
    if (!isNative()) {
      if (typeof deps.queryGeoPermission === 'function') return deps.queryGeoPermission();
      return 'unknown';
    }
    if (isExpoNative()) {
      try {
        const res = await expoBridgeRequest('expo:permission:query');
        const status = (res && res.status) || 'unknown';
        notifyPermissionChange(status);
        return status;
      } catch (e) {
        log('expo permission query failed', e.message);
        return 'unknown';
      }
    }
    const Geo = getGeolocationPlugin();
    if (!Geo || !Geo.checkPermissions) return 'unknown';
    try {
      const r = await Geo.checkPermissions();
      const loc = r.location || r.coarseLocation || 'prompt';
      if (loc === 'granted') return 'granted';
      if (loc === 'denied') return 'denied';
      return 'prompt';
    } catch (e) {
      log('checkPermissions failed', e.message);
      return 'unknown';
    }
  }

  async function requestPermissions() {
    if (!isNative()) return queryPermissionStatus();
    if (isExpoNative()) {
      try {
        const res = await expoBridgeRequest('expo:permission:request', { background: true });
        const status = (res && res.status) || 'denied';
        log('expo requestPermissions', status);
        notifyPermissionChange(status);
        return status;
      } catch (e) {
        log('expo requestPermissions error', e.message);
        return 'denied';
      }
    }
    const Geo = getGeolocationPlugin();
    if (!Geo || !Geo.requestPermissions) return 'unavailable';
    try {
      const r = await Geo.requestPermissions({ permissions: ['location', 'coarseLocation'] });
      const loc = r.location || r.coarseLocation || 'denied';
      log('requestPermissions', loc);
      return loc === 'granted' ? 'granted' : loc;
    } catch (e) {
      log('requestPermissions error', e.message);
      return 'denied';
    }
  }

  async function startBackgroundFoundation(active) {
    if (!isNative() || !isShiftActive()) return false;
    backgroundActive = !!active;
    if (backgroundActive) {
      log('background foundation active — verify on locked-phone drive');
    } else {
      log('background foundation inactive — Always location required');
      notifyPermissionChange('foreground-only');
    }
    return backgroundActive;
  }

  function stopBackgroundFoundation() {
    backgroundActive = false;
  }

  function isShiftActive() {
    if (typeof deps.isShiftTracking === 'function') return deps.isShiftTracking();
    if (global.MPTracking && global.MPTracking.isActive) return global.MPTracking.isActive();
    return false;
  }

  async function startExpoWatch() {
    if (!global.MPExpoBridge) {
      log('MPExpoBridge unavailable');
      return false;
    }
    global.__onExpoNativeLocation = function (msg) {
      if (deps.handlePos && msg) {
        const p = expoMsgToBrowserPosition(msg);
        if (p) deps.handlePos(p);
      }
    };
    try {
      const res = await expoBridgeRequest('expo:tracking:start', {
        background:
          isShiftActive() &&
          (!global.MPTrackingMode || global.MPTrackingMode.usesBackgroundTracking()),
      });
      if (res && res.ok !== false) {
        const bgActive = !!res.backgroundActive;
        log('expo watch started', { backgroundActive: bgActive });
        await startBackgroundFoundation(bgActive);
        return { ok: true, backgroundActive: bgActive };
      }
    } catch (e) {
      log('startExpoWatch failed', e.message);
    }
    return { ok: false, backgroundActive: false };
  }

  function stopExpoWatch() {
    if (global.MPExpoBridge && global.MPExpoBridge.request) {
      global.MPExpoBridge.request('expo:tracking:stop').catch(function () {});
    }
    global.__onExpoNativeLocation = null;
    stopBackgroundFoundation();
  }

  async function startNativeWatch() {
    if (isExpoNative()) return startExpoWatch();
    const Geo = getGeolocationPlugin();
    if (!Geo || !Geo.watchPosition) {
      log('Geolocation plugin unavailable');
      return false;
    }
    if (nativeWatchId !== null) return true;
    try {
      nativeWatchId = await Geo.watchPosition(
        {
          enableHighAccuracy: true,
          timeout: 30000,
          maximumAge: 0,
        },
        function (position, err) {
          if (err) {
            log('watchPosition error', err.message || String(err));
            return;
          }
          if (deps.handlePos && position) {
            const p = capToBrowserPosition(position);
            if (p) deps.handlePos(p);
          }
        }
      );
      log('watch started', { id: nativeWatchId });
      await startBackgroundFoundation(false);
      return { ok: true, backgroundActive: false };
    } catch (e) {
      log('startNativeWatch failed', e.message);
      nativeWatchId = null;
      return { ok: false, backgroundActive: false };
    }
  }

  function stopNativeWatch() {
    if (isExpoNative()) {
      stopExpoWatch();
      return;
    }
    const Geo = getGeolocationPlugin();
    if (Geo && Geo.clearWatch && nativeWatchId !== null) {
      try {
        Geo.clearWatch({ id: nativeWatchId });
      } catch (e) {
        log('clearWatch error', e.message);
      }
    }
    nativeWatchId = null;
    stopBackgroundFoundation();
  }

  async function enableTracking(fromUserGesture) {
    if (!deps) return false;
    if (!isNative()) return false;

    if (deps.updateGpsUi) deps.updateGpsUi('Finding GPS…');
    if (deps.showStatus) deps.showStatus('Finding GPS…');

    const perm = fromUserGesture ? await requestPermissions() : await queryPermissionStatus();
    if (perm !== 'granted' && perm !== 'foreground-only' && fromUserGesture) {
      const retry = await requestPermissions();
      if (retry !== 'granted' && retry !== 'foreground-only') {
        if (deps.updateGpsUi)
          deps.updateGpsUi(
            global.trackingErrorMessage ? global.trackingErrorMessage('denied') : 'Location denied'
          );
        if (deps.hideStatus) deps.hideStatus();
        return false;
      }
    } else if (perm !== 'granted' && perm !== 'foreground-only') {
      if (deps.updateGpsUi) deps.updateGpsUi('Enable location so AutoPilot can start recording.');
      if (deps.hideStatus) deps.hideStatus();
      return false;
    }

    stopNativeWatch();
    const watchResult = await startNativeWatch();
    if (watchResult.ok) {
      try {
        localStorage.setItem('mp_location_choice', 'granted');
        localStorage.setItem('mp_onboard_flag_location', 'true');
      } catch (e) {}
      if (global.gpsLocked !== undefined) global.gpsLocked = true;
      if (perm === 'foreground-only' || !watchResult.backgroundActive) {
        if (deps.updateGpsUi) {
          deps.updateGpsUi('Allow Always location in Settings for background miles.');
        }
      } else if (deps.updateGpsUi) {
        deps.updateGpsUi(null);
      }
      if (deps.hideStatus) deps.hideStatus();
      log('enableTracking ok', { backgroundActive: watchResult.backgroundActive });
      return watchResult;
    }
    if (deps.updateGpsUi) deps.updateGpsUi('GPS unavailable');
    if (deps.hideStatus) deps.hideStatus();
    return false;
  }

  function stopTracking() {
    if (!isNative()) return;
    stopNativeWatch();
  }

  function getNativePermissionCopy() {
    return { whenInUse: NATIVE_LOCATION_WHEN_IN_USE, background: NATIVE_LOCATION_ALWAYS };
  }

  function getLogs() {
    return logBuffer.slice();
  }

  function getPermission() {
    return lastPermissionStatus;
  }

  function onPermissionChange(fn) {
    if (typeof fn === 'function') permissionListeners.push(fn);
  }

  async function openAppSettings() {
    if (!isExpoNative()) return false;
    try {
      const res = await expoBridgeRequest('expo:settings:open');
      return !!(res && res.ok);
    } catch (e) {
      log('openAppSettings failed', e.message);
      return false;
    }
  }

  function getHealthBackground() {
    if (isWebShell()) {
      return {
        state: 'ok',
        status: getMode() === 'pwa' ? 'PWA mode' : 'Browser mode',
        hint: global.MPPlatform.getBackgroundTrackingNote(),
        action: '',
      };
    }
    if (lastPermissionStatus === 'foreground-only') {
      return {
        state: 'warn',
        status: 'Foreground only',
        hint: 'Set Location to Always in iPhone Settings for background mileage.',
        action: 'settings',
      };
    }
    const perm = localStorage.getItem('mp_location_choice');
    if (perm === 'granted' || lastPermissionStatus === 'granted') {
      return {
        state: backgroundActive ? 'ok' : 'warn',
        status: backgroundActive ? 'Background active' : 'Foreground only',
        hint: backgroundActive
          ? 'Background location active — verify on a real drive.'
          : 'Start a shift with Always location for background miles.',
        action: backgroundActive ? '' : 'settings',
      };
    }
    return {
      state: 'warn',
      status: 'Needs location',
      hint: NATIVE_LOCATION_WHEN_IN_USE,
      action: 'gps',
    };
  }

  global.MPTrackingProvider = {
    init: init,
    getMode: getMode,
    isNative: isNative,
    isWebShell: isWebShell,
    isExpoNative: isExpoNative,
    enableTracking: enableTracking,
    startTracking: enableTracking,
    stopTracking: stopTracking,
    queryPermissionStatus: queryPermissionStatus,
    requestPermissions: requestPermissions,
    getPermission: getPermission,
    onPermissionChange: onPermissionChange,
    openAppSettings: openAppSettings,
    getNativePermissionCopy: getNativePermissionCopy,
    getHealthBackground: getHealthBackground,
    getLogs: getLogs,
    NATIVE_LOCATION_WHEN_IN_USE: NATIVE_LOCATION_WHEN_IN_USE,
    NATIVE_LOCATION_ALWAYS: NATIVE_LOCATION_ALWAYS,
  };
})(typeof window !== 'undefined' ? window : global);
